content:
{
  "sentences": [
    {
      "text": "我喜歡打籃球，也喜歡踢足球。",
      "pinyin": "Wǒ xǐhuān dǎ lánqiú, yě xǐhuān tī zúqiú.",
      "pinyin_numeric": "wo3 xi3huan1 da3 lan2qiu2, ye3 xi3huan1 ti1 zu2qiu2.",
      "translation_en": "I like playing basketball and also like playing soccer.",
      "translation_ko": "저는 농구하는 것을 좋아하고, 축구하는 것도 좋아합니다."
    },
    {
      "text": "你週末常常做什麼休閒活動？",
      "pinyin": "Nǐ zhōumò chángcháng zuò shénme xiūxián huódòng?",
      "pinyin_numeric": "ni3 zhou1mo4 chang2chang2 zuo4 shen2me xiu1xian2 huo2dong4?",
      "translation_en": "What leisure activities do you often do on weekends?",
      "translation_ko": "주말에 자주 어떤 여가 활동을 하시나요?"
    },
    {
      "text": "他喜歡下棋，可是我不會。",
      "pinyin": "Tā xǐhuān xià qí, kěshì wǒ bù huì.",
      "pinyin_numeric": "ta1 xi3huan1 xia4 qi2, ke3shi4 wo3 bu4 hui4.",
      "translation_en": "He likes playing chess, but I don't know how.",
      "translation_ko": "그는 체스 두는 것을 좋아하지만, 저는 할 줄 모릅니다."
    },
    {
      "text": "我們要不要一起去爬山？",
      "pinyin": "Wǒmen yào bù yào yīqǐ qù pá shān?",
      "pinyin_numeric": "wo3men yao4 bu4 yao4 yi1qi3 qu4 pa2 shan1?",
      "translation_en": "Do you want to go hiking together?",
      "translation_ko": "우리 같이 등산하러 갈래요?"
    },
    {
      "text": "她喜歡看小說，有時候也看漫畫。",
      "pinyin": "Tā xǐhuān kàn xiǎoshuō, yǒu shíhou yě kàn mànhuà.",
      "pinyin_numeric": "ta1 xi3huan1 kan4 xiao3shuo1, you3 shi2hou4 ye3 kan4 man4hua4.",
      "translation_en": "She likes reading novels, and sometimes also reads comics.",
      "translation_ko": "그녀는 소설 읽는 것을 좋아하고, 가끔 만화도 봅니다."
    },
    {
      "text": "我很少打電動，因為太忙了。",
      "pinyin": "Wǒ hěn shǎo dǎ diàndòng, yīnwèi tài máng le.",
      "pinyin_numeric": "wo3 hen3 shao3 da3 dian4dong4, yin1wei4 tai4 mang2 le5.",
      "translation_en": "I rarely play video games because I'm too busy.",
      "translation_ko": "저는 게임을 거의 하지 않는데, 너무 바쁘기 때문입니다."
    },
    {
      "text": "你喜歡聽廣播還是看演唱會？",
      "pinyin": "Nǐ xǐhuān tīng guǎngbò háishì kàn yǎnchànghuì?",
      "pinyin_numeric": "ni3 xi3huan1 ting1 guang3bo4 hai2shi4 kan4 yan3chang4hui4?",
      "translation_en": "Do you like listening to the radio or going to concerts?",
      "translation_ko": "라디오 듣는 것을 좋아하세요, 아니면 콘서트 보는 것을 좋아하세요?"
    },
    {
      "text": "他從來不運動，只喜歡看球賽。",
      "pinyin": "Tā cónglái bù yùndòng, zhǐ xǐhuān kàn qiúsài.",
      "pinyin_numeric": "ta1 cong2lai2 bu4 yun4dong4, zhi3 xi3huan1 kan4 qiu2sai4.",
      "translation_en": "He never exercises; he only likes watching ball games.",
      "translation_ko": "그는 운동을 전혀 하지 않고, 경기 보는 것만 좋아합니다."
    },
    {
      "text": "放假的時候，我喜歡騎腳踏車去公園。",
      "pinyin": "Fàngjià de shíhou, wǒ xǐhuān qí jiǎotàchē qù gōngyuán.",
      "pinyin_numeric": "fang4jia4 de5 shi2hou4, wo3 xi3huan1 qi2 jiao3ta4che1 qu4 gong1yuan2.",
      "translation_en": "During holidays, I like riding a bicycle to the park.",
      "translation_ko": "휴가 때 저는 자전거를 타고 공원에 가는 것을 좋아합니다."
    },
    {
      "text": "你喜歡養寵物嗎？我養了一隻貓。",
      "pinyin": "Nǐ xǐhuān yǎng chǒngwù ma? Wǒ yǎng le yī zhī māo.",
      "pinyin_numeric": "ni3 xi3huan1 yang3 chong3wu4 ma0? wo3 yang3 le5 yi1 zhi1 mao1.",
      "translation_en": "Do you like keeping pets? I have a cat.",
      "translation_ko": "반려동물 키우는 것을 좋아하세요? 저는 고양이 한 마리를 키우고 있습니다."
    }
  ]
}
